import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';

export default function Counter() {
  const [count, setCount] = useState(0);

  return (
    <View>
      <Text>You pressed {count} times</Text>
      <Button title="Press me" onPress={() => setCount(count + 1)} />
    </View>
  );
}

slides.content:
You can call `useState` multiple times for different pieces of state.

```jsx
const [name, setName] = useState('');
const [age, setAge] = useState(0);
const [isStudent, setIsStudent] = useState(false);
```

Each piece of state is independent. It's common to split state into multiple variables rather than one big object, especially when they are updated separately.

**Never modify state directly!** Always use the setter function.

```jsx
// ❌ Wrong
count = count + 1;

// ✅ Correct
setCount(count + 1);
```
Direct assignment won't trigger a re‑render and can lead to bugs.
